    async function get_string() {
        // let res = await fetch("http://localhost:5000/anal", {
        //   method: "GET",
        //   mode: "no-cors",


        // });
        // let resJson = await res.json();
        // console.log(resJson)

        fetch("http://localhost:5000/anal")
            .then(data => {
                return data.json();
            })
            .then(post => {
                console.log(post.title);
            });
            
    }









    return (
        <div className='analytics_master'>
            <button onClick={get_string}>Get analytics</button>
        </div>
    )
}

export default Analytic
